CREATE DATABASE AIRLINE_COMPANY; 
USE AIRLINE_COMPANY;
CREATE TABLE AIRLINE_COMPANY(CID INT(5) NOT NULL, CNAME VARCHAR(50), CPHONE INT(10), CEMAIL VARCHAR(50), PRIMARY KEY(CID));
CREATE TABLE AIRPLANE(PID INT(5) NOT NULL, PMODEL VARCHAR(50), PYEAR INT(4), PCAPACITY INT(3), CID INT(5) NOT NULL, PRIMARY KEY(PID), FOREIGN KEY(CID) REFERENCES AIRLINE_COMPANY(CID));
CREATE TABLE STAFF(SSSN INT(10) NOT NULL, SNAME VARCHAR(50), SPHONE INT(10), SJOBTITLE VARCHAR(50), SAGE INT(2), CID INT(5) NOT NULL, PRIMARY KEY(SSSN), FOREIGN KEY(CID) REFERENCES AIRLINE_COMPANY(CID));
CREATE TABLE AIRPORT(AID INT(5) NOT NULL, ANAME VARCHAR(50), ALOCATION VARCHAR(50), PRIMARY KEY(AID));
CREATE TABLE PASSENGER(PSSN INT(10) NOT NULL, PNAME VARCHAR(50), PPHONE INT(10), PADDRESS VARCHAR(50), AGE INT(2), PRIMARY KEY(PSSN));
CREATE TABLE FLIGHT(FID INT(5) NOT NULL, FDATE DATE, FDESTINATION VARCHAR(50), CID INT(5) NOT NULL, PRIMARY KEY(FID), FOREIGN KEY(CID) REFERENCES AIRLINE_COMPANY(CID));
CREATE TABLE TICKET(TID INT(7), TSEAT INT(3), TCOST INT(4), FID INT(5) NOT NULL, PSSN INT(10) NOT NULL, PRIMARY KEY(TID), FOREIGN KEY(FID) REFERENCES FLIGHT(FID), FOREIGN KEY(PSSN) REFERENCES PASSENGER(PSSN));
CREATE TABLE CONNECTS(CID INT(5) NOT NULL, AID INT(5) NOT NULL, FOREIGN KEY(CID) REFERENCES AIRLINE_COMPANY(CID), FOREIGN KEY(AID) REFERENCES AIRPORT(AID));
CREATE TABLE BOOKS(PSSN INT(10) NOT NULL, FID INT(5) NOT NULL, FOREIGN KEY(PSSN) REFERENCES PASSENGER(PSSN), FOREIGN KEY(FID) REFERENCES FLIGHT(FID));